mapper.update:
UPDATE lottery_pool
prize_type = #{prizeType}, prize_name = #{prizeName}, prize_image = #{prizeImage}, coupon_id = #{couponId}, balance_amount = #{balanceAmount}, probability = #{probability}, total_stock = #{totalStock}, remaining_stock = #{remainingStock}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT lr.*
FROM lottery_record lr


        AND lr.prize_type = #{prizeType}


        AND lr.fulfillment_status = #{fulfillmentStatus}


ORDER BY lr.create_time DESC
